+// ═══════════════════════════════════════════════════════════════════════════
+// 3. Strict mode denies unknown capabilities
+// ═══════════════════════════════════════════════════════════════════════════
+
+#[test]
+fn ui_denied_in_strict_mode_not_in_default_caps() {
+    let dir = tempdir().expect("tempdir");
+    let tools = ToolRegistry::new(&[], dir.path(), None);
+    let http = HttpConnector::with_defaults();
