+    let policy = strict_default();
+    let ctx = make_ctx(&tools, &http, &policy);
+    let call = make_call(
+        "ui-strict",
+        "ui",
+        "ui",
+        json!({"op": "notify", "message": "hello"}),
+    );
+
+    run_async(async {
+        let result = dispatch_host_call_shared(&ctx, call).await;
