+        "schema": "pi.ext.trial_selection.v1",
+        "seed": seed,
+        "requested_sample_size": sample_size,
+        "actual_sample_size": selected.len(),
+        "filter": {
+            "tier_range": filter.tier_range,
+            "source_category": filter.source_category,
+        },
+        "selected_ids": selected,
+    })
+    .to_string()
+}
