+    let result = run_async(async move { connector.dispatch(&call).await.unwrap() });
+
+    assert!(
+        !result.is_error,
+        "http should be allowed when TLS not required: {:?}",
+        result.error
+    );
+    assert_eq!(
+        result.output.get("status").and_then(Value::as_u64),
+        Some(200)
+    );
+}
